/* oms-master-commonCodeBatch-sql-oracle.xml - insertIntfTableCommonCode */
INSERT INTO TORDER_INTF_MAL_COM (
     OWKEY
   , COMHDKEY
   , INSERTSYSTM
   , COMHDNM
   , UPRCOMHDKEY
   , COMDTKEY
   , COMDTNM
   , UPRCOMDTKEY
   , HDDELYN
   , DTDELYN
   , DELYN
   , REQUESTDT
   , IFID
   , INSERTDATE
   , INSERTURKEY
   , UPDATEDATE
   , UPDATEURKEY
) VALUES (
     #{owkey}
   , #{comhdkey}
   , #{insertsystm}
   , #{comhdnm}
   , #{uprcomhdkey}
   , #{comdtkey}
   , #{comdtnm}
   , #{uprcomdtkey}
   , #{hddelyn}
   , #{dtdelyn}
   , COALESCE(#{delyn}, 'N')
   , #{requestDt}
   , #{interfaceId}
   , #{sysdate}
   , #{interfaceUrkey}
   , #{sysdate}
   , #{interfaceUrkey}

)

		/* oms-master-commonCodeBatch-sql-oracle.xml - insertWmsCommonCodeIntfInfo */
		INSERT INTO TORDER_INTF_WMS_COM
		 (
		      CTKEY
			, OWKEY
            , COMHDKEY
            , COMHDNM
            , UPRCOMHDKEY
            , COMDTKEY
            , COMDTNM
            , UPRCOMDTKEY
            , DELYN
		    , REQUESTDT
		    , IFID
		    , INSERTDATE
		    , INSERTURKEY
		    , UPDATEDATE
		    , UPDATEURKEY
		) VALUES (
              #{ctkey}
		    , #{owkey}
            , #{comhdkey}
            , #{comhdnm}
            , #{uprcomhdkey}
            , #{comdtkey}
            , #{comdtnm}
            , #{uprcomdtkey}
            , COALESCE(#{delyn}, 'N')
		    , #{requestDt}
		    , #{interfaceId}
			, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	        , #{urkey}
		    , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	        , #{urkey}
		)

	/* oms-master-commonCodeBatch-sql-oracle.xml - insertWmsCommonCodeCtgIntfInfo */
	INSERT INTO TORDER_INTF_WMS_CTG
	 (
	      CTKEY
	    , OWKEY
	    , CTGKEY
	    , CTGNM
	    , CTGLV
	    , UPPERCTGKEY
	    , REQUESTDT
	    , IFID
	    , INSERTDATE
	    , INSERTURKEY
	    , UPDATEDATE
	    , UPDATEURKEY
	) VALUES (
	      #{ctkey}
	    , #{owkey}
	    , #{ctgkey}
	    , #{ctgnm}
	    , #{ctglv}
	    , #{upperctgkey}
	    , #{requestDt}
	    , #{interfaceId}
		, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
        , #{urkey}
	    , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
        , #{urkey}
	)

		/* oms-master-commonCodeBatch-sql-oracle.xml - insertWmsCommonCodeCtgIntfInfo */
		INSERT INTO TORDER_INTF_WMS_CTG
		 (
		      CTKEY
		    , OWKEY
		    , CTGKEY
		    , CTGNM
		    , CTGLV
		    , UPPERCTGKEY
		    , REQUESTDT
		    , IFID
		    , INSERTDATE
		    , INSERTURKEY
		    , UPDATEDATE
		    , UPDATEURKEY
		) SELECT #{ctkey}
		       , CTG.OWKEY
		       , CTG.CTGKEY
               , CTG.CTGNM
               , CTG.CTGLV
               , CTG.UPPERCTGKEY
		       , #{requestDt}
		       , #{interfaceId}
			   , #{sysdate}
	           , #{interfaceUrkey}
		       , #{sysdate}
	           , #{interfaceUrkey}
		FROM TORDER_MST_CTG CTG
		INNER JOIN TORDER_EAI_COMCD_BATCH BAT
		       ON CTG.CTGKEY = BAT.COMDTKEY
		WHERE BAT.COMHDKEY IN ('DIV_MIN','DIV_MID', 'DIV_MAX')
          AND BAT.TRN_ID = #{trnId}

